#!/bin/bash

# Flexible Backup Script
# Compresses user-specified directories into a timestamped tar.gz archive

# Color codes for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

# Generate timestamp for backup filename
TIMESTAMP=$(date +"%Y%m%d_%H%M%S")
BACKUP_DIR="${BACKUP_DEST:-./backups}"
BACKUP_FILE="${BACKUP_DIR}/backup_${TIMESTAMP}.tar.gz"

# Function to display usage
usage() {
    echo -e "${YELLOW}Usage:${NC} $0 <directory1> [directory2] [directory3] ..."
    echo ""
    echo "  Compresses one or more directories into a timestamped tar.gz archive."
    echo ""
    echo "  Options:"
    echo "    -h, --help       Show this help message"
    echo "    -o, --output     Specify custom output file path"
    echo "    -v, --verbose    Enable verbose output during compression"
    echo ""
    echo "  Environment Variables:"
    echo "    BACKUP_DEST      Set custom backup destination directory (default: ./backups)"
    echo ""
    echo "  Examples:"
    echo "    $0 /home/user/documents /var/log"
    echo "    $0 -v -o /tmp/mybackup.tar.gz /etc /home"
    echo "    BACKUP_DEST=/mnt/nas $0 /home/user/projects"
}

# Function to log messages
log() {
    local level="$1"
    local message="$2"
    local timestamp
    timestamp=$(date +"%Y-%m-%d %H:%M:%S")

    case "$level" in
        INFO)
            echo -e "${GREEN}[${timestamp}] [INFO]${NC} ${message}"
            ;;
        WARN)
            echo -e "${YELLOW}[${timestamp}] [WARN]${NC} ${message}"
            ;;
        ERROR)
            echo -e "${RED}[${timestamp}] [ERROR]${NC} ${message}"
            ;;
    esac
}

# Parse options
VERBOSE=""
CUSTOM_OUTPUT=""
DIRECTORIES=()

while [[ $# -gt 0 ]]; do
    case "$1" in
        -h|--help)
            usage
            exit 0
            ;;
        -v|--verbose)
            VERBOSE="-v"
            shift
            ;;
        -o|--output)
            if [[ -z "$2" || "$2" == -* ]]; then
                log "ERROR" "Option -o requires an output file path argument."
                exit 1
            fi
            CUSTOM_OUTPUT="$2"
            shift 2
            ;;
        -*)
            log "ERROR" "Unknown option: $1"
            usage
            exit 1
            ;;
        *)
            DIRECTORIES+=("$1")
            shift
            ;;
    esac
done

# Check if any directories were provided
if [[ ${#DIRECTORIES[@]} -eq 0 ]]; then
    log "ERROR" "No directories specified."
    usage
    exit 1
fi

# Override backup file if custom output was specified
if [[ -n "$CUSTOM_OUTPUT" ]]; then
    BACKUP_FILE="$CUSTOM_OUTPUT"
    BACKUP_DIR=$(dirname "$BACKUP_FILE")
fi

# Validate each directory
VALID_DIRECTORIES=()
INVALID_COUNT=0

for dir in "${DIRECTORIES[@]}"; do
    # Resolve to absolute path
    resolved_dir=$(realpath "$dir" 2>/dev/null)

    if [[ -z "$resolved_dir" ]]; then
        log "WARN" "Cannot resolve path: '$dir' — skipping."
        ((INVALID_COUNT++))
        continue
    fi

    if [[ ! -e "$resolved_dir" ]]; then
        log "WARN" "Path does not exist: '$resolved_dir' — skipping."
        ((INVALID_COUNT++))
        continue
    fi

    if [[ ! -d "$resolved_dir" ]]; then
        log "WARN" "Path is not a directory: '$resolved_dir' — skipping."
        ((INVALID_COUNT++))
        continue
    fi

    if [[ ! -r "$resolved_dir" ]]; then
        log "WARN" "No read permission for: '$resolved_dir' — skipping."
        ((INVALID_COUNT++))
        continue
    fi

    VALID_DIRECTORIES+=("$resolved_dir")
done

# Check if we have any valid directories left
if [[ ${#VALID_DIRECTORIES[@]} -eq 0 ]]; then
    log "ERROR" "No valid directories to back up. Aborting."
    exit 1
fi

if [[ $INVALID_COUNT -gt 0 ]]; then
    log "WARN" "${INVALID_COUNT} director(ies) were skipped due to errors."
fi

# Create backup destination directory if it doesn't exist
if [[ ! -d "$BACKUP_DIR" ]]; then
    log "INFO" "Creating backup destination directory: ${BACKUP_DIR}"
    mkdir -p "$BACKUP_DIR"
    if [[ $? -ne 0 ]]; then
        log "ERROR" "Failed to create backup directory: ${BACKUP_DIR}"
        exit 1
    fi
fi

# Check available disk space (rough estimate)
# Get total size of directories to back up (in KB)
TOTAL_SIZE=0
for dir in "${VALID_DIRECTORIES[@]}"; do
    dir_size=$(du -sk "$dir" 2>/dev/null | awk '{print $1}')
    TOTAL_SIZE=$((TOTAL_SIZE + dir_size))
done

# Get available space in backup destination (in KB)
AVAILABLE_SPACE=$(df -k "$BACKUP_DIR" 2>/dev/null | awk 'NR==2 {print $4}')

if [[ -n "$AVAILABLE_SPACE" && "$AVAILABLE_SPACE" -gt 0 ]]; then
    # Compressed size is typically smaller, but check if raw size exceeds available space
    if [[ $TOTAL_SIZE -gt $AVAILABLE_SPACE ]]; then
        log "WARN" "Source directories total $(numfmt --to=iec --from-unit=1024 ${TOTAL_SIZE} 2>/dev/null || echo "${TOTAL_SIZE}K") but only $(numfmt --to=iec --from-unit=1024 ${AVAILABLE_SPACE} 2>/dev/null || echo "${AVAILABLE_SPACE}K") available."
        log "WARN" "Compression may reduce the size, but backup might fail if space is insufficient."
    fi
fi

# Display backup summary
log "INFO" "Starting backup process..."
log "INFO" "Directories to back up:"
for dir in "${VALID_DIRECTORIES[@]}"; do
    dir_size=$(du -sh "$dir" 2>/dev/null | awk '{print $1}')
    echo "         - ${dir} (${dir_size})"
done
log "INFO" "Backup destination: ${BACKUP_FILE}"

# Perform the backup using tar
log "INFO" "Compressing directories..."

START_TIME=$(date +%s)

tar -czf "$BACKUP_FILE" $VERBOSE "${VALID_DIRECTORIES[@]}" 2>&1
TAR_EXIT_CODE=$?

END_TIME=$(date +%s)
ELAPSED=$((END_TIME - START_TIME))

# Check if tar succeeded
if [[ $TAR_EXIT_CODE -eq 0 ]]; then
    BACKUP_SIZE=$(du -sh "$BACKUP_FILE" 2>/dev/null | awk '{print $1}')
    log "INFO" "Backup completed successfully!"
    log "INFO" "Archive: ${BACKUP_FILE}"
    log "INFO" "Archive size: ${BACKUP_SIZE}"
    log "INFO" "Time elapsed: ${ELAPSED} second(s)"

    # Verify the archive integrity
    log "INFO" "Verifying archive integrity..."
    tar -tzf "$BACKUP_FILE" > /dev/null 2>&1
    if [[ $? -eq 0 ]]; then
        log "INFO" "Archive integrity verified — backup is valid."
    else
        log "WARN" "Archive integrity check failed. The backup may be corrupted."
        exit 2
    fi
elif [[ $TAR_EXIT_CODE -eq 1 ]]; then
    log "WARN" "Backup completed with warnings (some files may have changed during archiving)."
    log "WARN" "Archive: ${BACKUP_FILE}"
    BACKUP_SIZE=$(du -sh "$BACKUP_FILE" 2>/dev/null | awk '{print $1}')
    log "INFO" "Archive size: ${BACKUP_SIZE}"
    log "INFO" "Time elapsed: ${ELAPSED} second(s)"
else
    log "ERROR" "Backup failed with exit code: ${TAR_EXIT_CODE}"
    # Clean up failed backup file
    if [[ -f "$BACKUP_FILE" ]]; then
        rm -f "$BACKUP_FILE"
        log "INFO" "Cleaned up incomplete backup file."
    fi
    exit 1
fi

exit 0